def _get_safe_env():
    """Create a sanitized environment for subprocess execution."""
    safe_env = {}
    
    # Only pass through necessary environment variables
    allowed_env_vars = [
        'PATH', 'HOME', 'USER', 'LANG', 'LC_ALL', 'LC_CTYPE',
        'TMPDIR', 'TEMP', 'TMP',
        'DISPLAY', 'XAUTHORITY',  # Needed for some LibreOffice operations
        'FONTCONFIG_PATH', 'FONTCONFIG_FILE',
        'SystemRoot', 'SYSTEMROOT',  # Windows
        'PROGRAMFILES', 'PROGRAMFILES(X86)',  # Windows
    ]
    
    for var in allowed_env_vars:
        if var in os.environ:
            safe_env[var] = os.environ[var]
    
    return safe_env


def batch_convert(input_files, output_dir, output_format):
    """
    Convert multiple files to a specified format.
    
    Args:
        input_files (list): List of input file paths.
        output_dir (str): Directory to save converted files.
        output_format (str): Target format.
    
    Returns:
        list: List of tuples (input_file, output_file, success, error_message).
    """
    results = []
    
    # Validate output directory
    output_dir_path = Path(output_dir).resolve()
    os.makedirs(str(output_dir_path), exist_ok=True)
    
    validated_format = _validate_format(output_format)
    
    for input_file in input_files:
        try:
            input_path = Path(input_file).resolve()
            output_name = f"{input_path.stem}.{validated_format}"
            output_file = str(output_dir_path / output_name)
            
            converted_path = convertDocument(str(input_file), output_file, output_format)
            results.append((str(input_file), converted_path, True, None))
        except Exception as e:
            results.append((str(input_file), None, False, str(e)))
    
    return results


